                    c[k] = v
                    cond(self).notify_all()
                    return v
        if lock is not None:
            with lock(self):
                try: return c[k]
                except KeyError:
                    v = method(self, *args, **kwargs)
                    c[k] = v
                    return v
        try: return c[k]
        except KeyError:
            v = method(self, *args, **kwargs)
            c[k] = v
            return v
    wrapper.cache = cache
    wrapper.cache_key = key
    wrapper.cache_lock = lock if lock is not None else cond
    wrapper.cache_condition = cond
    wrapper.cache_clear = lambda self: cache(self).clear()
    return wrapper

