    def __getitem__(self, key, cache_getitem=Cache.__getitem__): v = cache_getitem(self, key); self._counter[key] += 1; return v
    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__): cache_setitem(self, key, value); self._counter[key] += 1
    def __delitem__(self, key, cache_delitem=Cache.__delitem__): self._counter.pop(key, None); cache_delitem(self, key)
    def popitem(self):
        if not self._counter: raise KeyError('%s is empty' % type(self).__name__)
        key = min(self._counter, key=self._counter.get)
        return key, self.pop(key)

class LRUCache(Cache):
    def __init__(self, maxsize, getsizeof=None): super().__init__(maxsize, getsizeof); self._order = collections.OrderedDict()
    def __getitem__(self, key, cache_getitem=Cache.__getitem__): v = cache_getitem(self, key); self._order.move_to_end(key); return v
    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__): cache_setitem(self, key, value); self._order[key] = None; self._order.move_to_end(key)
    def __delitem__(self, key, cache_delitem=Cache.__delitem__): self._order.pop(key, None); cache_delitem(self, key)
    def popitem(self):
        if not self._order: raise KeyError('%s is empty' % type(self).__name__)
        key = next(iter(self._order))
        return key, self.pop(key)

class RRCache(Cache):
    def __init__(self, maxsize, choice=random.choice, getsizeof=None): super().__init__(maxsize, getsizeof); self._choice = choice
    @property
    def choice(self): return self._choice
    def popitem(self):
        if not self: raise KeyError('%s is empty' % type(self).__name__)
        key = self._choice(tuple(self._data))
        return key, self.pop(key)

class _TimedCache(Cache):
    class _Timer:
        def __init__(self, timer): self._timer = timer; self._nest = 0; self._time = None
        def __call__(self): return self._time if self._nest else self._timer()
        def __enter__(self): self._nest += 1; self._time = self._timer(); return self._time
        def __exit__(self, *exc): self._nest -= 1
        def __reduce__(self): return type(self), (self._timer,)
        def __getattr__(self, name): return getattr(self._timer, name)
    def __init__(self, maxsize, timer=time.monotonic, getsizeof=None): super().__init__(maxsize, getsizeof); self._timer = _TimedCache._Timer(timer)
    def __repr__(self, cache_repr=Cache.__repr__): return cache_repr(self)
    def __len__(self, cache_len=Cache.__len__): return cache_len(self)
    @property
    def currsize(self): return super().currsize
    @property
    def timer(self): return self._timer
    def clear(self): self.expire(); self._data.clear(); self._size.clear(); self._currsize = 0
    def get(self, *args, **kwargs): return super().get(*args, **kwargs)
    def pop(self, *args, **kwargs): return super().pop(*args, **kwargs)

